import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1].split('\\\\')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion', ''))
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
        if bv != av:
            print(f'  {proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
