    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
        if bv == av:
            print(f'  {proj}: {pkg} {bv}')
